/**
 * Render the two printable survey views to PDF so they can be shipped in the
 * repo and attached to invitation .eml files generated by the CMS.
 *
 *   attachments/vragenlijst.pdf        — live survey print (src/js/print.js),
 *                                        rendered with no values. Keeps the
 *                                        "Organisatie / Charter-code" meta
 *                                        header and is the print you'd get
 *                                        if you clicked "Afdrukken" from the
 *                                        live form while it was empty.
 *
 *   attachments/blanco-vragenlijst.pdf — standalone blanco version from
 *                                        tools/printbare-vragenlijst.html.
 *                                        No personal fields, safe for
 *                                        distribution.
 *
 *   attachments/handleiding.pdf        — print render of /handleiding
 *                                        (handleiding.html). Uses the
 *                                        page's own print stylesheet.
 *
 * Run with:   node scripts/generate-print-pdfs.js
 */

import { createServer } from 'node:http';
import { readFile, stat, writeFile, mkdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { extname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import puppeteer from 'puppeteer-core';

const __filename = fileURLToPath(import.meta.url);
const ROOT = resolve(__filename, '..', '..');
const OUT_DIR = join(ROOT, 'attachments');

const MIME = {
  '.html': 'text/html; charset=utf-8',
  '.js':   'application/javascript; charset=utf-8',
  '.mjs':  'application/javascript; charset=utf-8',
  '.css':  'text/css; charset=utf-8',
  '.json': 'application/json; charset=utf-8',
  '.svg':  'image/svg+xml',
  '.png':  'image/png',
  '.jpg':  'image/jpeg',
  '.jpeg': 'image/jpeg',
  '.woff': 'font/woff',
  '.woff2':'font/woff2'
};

function findChromeBinary() {
  const candidates = [
    '/root/.cache/puppeteer/chrome/linux-147.0.7727.56/chrome-linux64/chrome',
    '/opt/pw-browsers/chromium-1194/chrome-linux/chrome',
    '/opt/pw-browsers/chromium/chrome',
    '/usr/bin/google-chrome',
    '/usr/bin/chromium',
    '/usr/bin/chromium-browser'
  ];
  for (const p of candidates) {
    if (existsSync(p)) return p;
  }
  throw new Error('No Chrome binary found');
}

async function serveRoot(port) {
  return new Promise((resolvePromise, rejectPromise) => {
    const server = createServer(async (req, res) => {
      try {
        let urlPath = decodeURIComponent(req.url.split('?')[0]);
        if (urlPath === '/' || urlPath === '') urlPath = '/index.html';
        if (urlPath === '/printbare-vragenlijst') urlPath = '/tools/printbare-vragenlijst.html';
        if (urlPath === '/handleiding') urlPath = '/handleiding.html';

        const filePath = join(ROOT, urlPath);
        if (!filePath.startsWith(ROOT)) {
          res.writeHead(403); res.end('Forbidden'); return;
        }
        try { await stat(filePath); } catch {
          res.writeHead(404); res.end('Not found: ' + urlPath); return;
        }
        const body = await readFile(filePath);
        const ext = extname(filePath).toLowerCase();
        res.writeHead(200, { 'Content-Type': MIME[ext] || 'application/octet-stream' });
        res.end(body);
      } catch (err) {
        res.writeHead(500); res.end(String(err));
      }
    });
    server.on('error', rejectPromise);
    server.listen(port, '127.0.0.1', () => resolvePromise(server));
  });
}

async function renderLiveSurveyBlankHtml() {
  // Mimic src/js/print.js with no values. Rather than wiring up the whole
  // app state, we generate an ephemeral HTML page that imports survey data,
  // runs the blank renderer, and replaces the document body. The PDF is
  // produced from that.
  const html = `<!DOCTYPE html>
<html lang="nl"><head><meta charset="UTF-8"><title>Vragenlijst</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
</head><body>
<div id="root">Laden\u2026</div>
<script type="module">
  import { SURVEY_STEPS, LIKERT_OPTIONS } from '/survey/survey-questions.js';
  window.__SURVEY_STEPS__ = SURVEY_STEPS;
  window.__LIKERT_OPTIONS__ = LIKERT_OPTIONS;
  window.__READY__ = true;
</script>
</body></html>`;
  return html;
}

async function main() {
  await mkdir(OUT_DIR, { recursive: true });

  const port = 4123;
  const server = await serveRoot(port);
  const base = `http://127.0.0.1:${port}`;

  const browser = await puppeteer.launch({
    executablePath: findChromeBinary(),
    args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage'],
    headless: 'new'
  });

  try {
    // ── 1. Blanco vragenlijst from /printbare-vragenlijst ───────────────
    {
      const page = await browser.newPage();
      await page.emulateMediaType('print');
      const target = `${base}/printbare-vragenlijst`;
      console.log('[pdf] Rendering', target);
      await page.goto(target, { waitUntil: 'networkidle0', timeout: 60000 });
      // Wait for the module to inject content
      await page.waitForFunction(() => {
        const root = document.getElementById('printRoot');
        return root && root.children.length > 0;
      }, { timeout: 20000 });
      // Give fonts a beat
      await page.evaluateHandle('document.fonts.ready');
      await new Promise(r => setTimeout(r, 400));

      const out = join(OUT_DIR, 'blanco-vragenlijst.pdf');
      await page.pdf({
        path: out,
        format: 'A4',
        printBackground: true,
        preferCSSPageSize: true,
        margin: { top: '18mm', right: '18mm', bottom: '20mm', left: '18mm' }
      });
      console.log('[pdf] \u2713', out);
      await page.close();
    }

    // ── 2. Vragenlijst from src/js/print.js (empty values) ──────────────
    //
    // We load the live print module off the compiled bundle and invoke its
    // blank-renderer path by stubbing the form & state before calling the
    // document generator. Simplest route: build the doc via a lightweight
    // inline script that imports print.js's internal helpers by re-running
    // the generator with no data.
    {
      const scratchPath = join(ROOT, '.pdf-scratch.html');
      const scratchHtml = await renderLiveSurveyBlankHtml();
      await writeFile(scratchPath, scratchHtml);

      const page = await browser.newPage();
      await page.emulateMediaType('print');
      await page.goto(`${base}/.pdf-scratch.html`, { waitUntil: 'networkidle0', timeout: 60000 });
      await page.waitForFunction(() => window.__READY__, { timeout: 20000 });

      // Inline the print-document generator (a trimmed, blank-only fork of
      // src/js/print.js). We keep the same CSS and markup so the output is
      // indistinguishable from what a user sees when they click "Afdrukken"
      // on an empty live form.
      const printModuleSrc = await readFile(join(ROOT, 'src/js/print.js'), 'utf8');
      // Extract the wrapInPage, generatePrintDocument, renderStep, renderFields,
      // renderField, renderInlineInput, renderTextarea, renderCheckbox,
      // renderRadioCards, renderRadioList, renderFieldGroup, renderInfoBlock,
      // renderLikert, esc, labelText, hasValue from the source.
      //
      // Rather than fragile surgery, we just strip the top-level imports and
      // exports, and eval it in the page.
      const stripped = printModuleSrc
        .replace(/^\s*import [^;]+;\s*$/gm, '')
        .replace(/^\s*export\s+/gm, '');

      await page.evaluate((src) => {
        // Provide minimal stand-ins for the imports that were stripped.
        window.state = { session: { orgName: '', orgCode: '' } };
        window.showErrorModal = () => {};
        window.SURVEY_STEPS = window.__SURVEY_STEPS__;
        window.LIKERT_OPTIONS = window.__LIKERT_OPTIONS__;

        // Alias the names the module expects after import-stripping.
        const prelude = `
          const state = window.state;
          const showErrorModal = window.showErrorModal;
          const SURVEY_STEPS = window.SURVEY_STEPS;
          const LIKERT_OPTIONS = window.LIKERT_OPTIONS;
        `;
        // Expose generatePrintDocument globally
        const wrapped = prelude + src + '\nwindow.__generatePrintDocument = generatePrintDocument;';
        // eslint-disable-next-line no-new-func
        new Function(wrapped)();
      }, stripped);

      const docHtml = await page.evaluate(() => {
        return window.__generatePrintDocument({}, '', '');
      });

      // Load the produced doc into the same page and print it.
      await page.setContent(docHtml, { waitUntil: 'domcontentloaded', timeout: 60000 });
      await page.emulateMediaType('print');
      try { await page.evaluateHandle('document.fonts.ready'); } catch {}
      await new Promise(r => setTimeout(r, 800));

      const out = join(OUT_DIR, 'vragenlijst.pdf');
      await page.pdf({
        path: out,
        format: 'A4',
        printBackground: true,
        preferCSSPageSize: true,
        margin: { top: '18mm', right: '18mm', bottom: '20mm', left: '18mm' }
      });
      console.log('[pdf] \u2713', out);

      await page.close();
      // Clean up scratch file
      await (await import('node:fs/promises')).unlink(scratchPath).catch(() => {});
    }

    // ── 3. Handleiding from /handleiding ────────────────────────────────
    {
      const page = await browser.newPage();
      await page.emulateMediaType('print');
      const target = `${base}/handleiding`;
      console.log('[pdf] Rendering', target);
      await page.goto(target, { waitUntil: 'domcontentloaded', timeout: 60000 });
      try { await page.evaluateHandle('document.fonts.ready'); } catch {}
      await new Promise(r => setTimeout(r, 800));

      const out = join(OUT_DIR, 'handleiding.pdf');
      await page.pdf({
        path: out,
        format: 'A4',
        printBackground: true,
        preferCSSPageSize: true,
        margin: { top: '16mm', right: '16mm', bottom: '18mm', left: '16mm' }
      });
      console.log('[pdf] \u2713', out);
      await page.close();
    }
  } finally {
    await browser.close();
    server.close();
  }
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});
